<body>

    <h1>Falling Sand Cellular Automata</h1>

    <div id="container">
        <!-- Canvas must be at least 400x400 CSS pixels -->
        <canvas id="sand" width="600" height="600"></canvas>

        <div id="controls">
            <button id="mat-sand">Sand</button>
            <button id="mat-water">Water</button>
            <button id="mat-wall">Wall</button>
            <button id="mat-acid">Acid</button>
            <button id="mat-empty">Eraser (Empty)</button>
        </div>

        <button id="clear">Clear Grid</button>
    </div>


    <script>
        // --- CONSTANTS AND INITIALIZATION ---

        const CANVAS_SIZE = 600; // CSS pixels for drawing
        const GRID_W = 80;      // Cells wide (must be >= 80)
        const GRID_H = 80;      // Cells high (must be >= 80)
        const CELL_PIXEL_SIZE = CANVAS_SIZE / GRID_W;

        const MATERIALS = {
            EMPTY: "empty",
            SAND: "sand",
            WATER: "water",
            WALL: "wall",
            ACID: "acid"
        };

        // Material colors for rendering (CSS/Canvas)
        const MATERIAL_COLORS = {
            [MATERIALS.EMPTY]: '#0f0f1a', // Background color
            [MATERIALS.SAND]: '#d2b48c',
            [MATERIALS.WATER]: '#64b5f6',
            [MATERIALS.WALL]: '#5d4037',
            [MATERIALS.ACID]: '#ff9800'
        };

        // --- GAME STATE ---
        let grid = [];
        let currentMaterial = MATERIALS.SAND;

        // --- DOM ELEMENTS ---
        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d');
        const materialButtons = {
            'mat-sand': MATERIALS.SAND,
            'mat-water': MATERIALS.WATER,
            'mat-wall': MATERIALS.WALL,
            'mat-acid': MATERIALS.ACID,
            'mat-empty': MATERIALS.EMPTY
        };

        // --- CORE SIMULATION OBJECT (API Contract) ---
        window.sim = {
            w: GRID_W,
            h: GRID_H,

            /**
             * Initializes the grid state to empty.
             */
            init() {
                grid = Array(GRID_H).fill(0).map(() => Array(GRID_W).fill(MATERIALS.EMPTY));
                this.draw();
            },

            /**
             * Gets the material at (x, y).
             * @param {number} x - Column index.
             * @param {number} y - Row index.
             * @returns {string} Material type.
             */
            get(x, y) {
                if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return MATERIALS.EMPTY;
                return grid[y][x];
            },

            /**
             * Sets the material at (x, y).
             * @param {number} x - Column index.
             * @param {number} y - Row index.
             * @param {string} material - Material type ("empty", "sand", etc.).
             */
            set(x, y, material) {
                if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return;
                grid[y][x] = material;
                this.draw(); // Redraw immediately upon programmatic set
            },

            /**
             * Clears the entire grid by setting all cells to empty.
             */
            clear() {
                for (let y = 0; y < GRID_H; y++) {
                    for (let x = 0; x < GRID_W; x++) {
                        grid[y][x] = MATERIALS.EMPTY;
                    }
                }
                this.draw();
            },

            /**
             * Advances the simulation by n steps synchronously.
             * @param {number} n - Number of ticks to run.
             */
            tick(n) {
                for (let i = 0; i < n; i++) {
                    this._step();
                }
            },

            /**
             * Internal function to perform one simulation step.
             * Processes movement bottom-up, left-to-right.
             */
            _step() {
                // We must process from the second row up (y=H-2) to ensure particles fall correctly.
                // The last row (H-1) is the solid boundary floor and does not move.
                for (let y = GRID_H - 2; y >= 0; y--) {
                    for (let x = 0; x < GRID_W; x++) {
                        const material = grid[y][x];

                        if (material === MATERIALS.EMPTY || material === MATERIALS.WALL) {
                            continue; // Walls don't move, empty space does nothing
                        }

                        // Optimization: Only process if the cell hasn't been moved into by a particle above it 
                        // in this same step iteration (though bottom-up processing handles most of this).
                        if (grid[y][x] !== material) {
                            continue;
                        }


                        let next_material = material;

                        switch (material) {
                            case MATERIALS.SAND:
                                // 1. Check straight down
                                if (this.get(x, y + 1) === MATERIALS.EMPTY) {
                                    // Fall straight down
                                    this.set(x, y + 1, MATERIALS.SAND);
                                    this.set(x, y, MATERIALS.EMPTY);
                                } else {
                                    // 2. Check diagonal (randomize direction checked first)
                                    const directions = [
                                        { dx: -1, dy: 1 }, // Down-Left
                                        { dx: 1, dy: 1 }   // Down-Right
                                    ];
                                    directions.sort(() => Math.random() - 0.5); // Randomize order

                                    for (const dir of directions) {
                                        const nx = x + dir.dx;
                                        const ny = y + dir.dy;

                                        if (nx >= 0 && nx < GRID_W && ny >= 0 && ny < GRID_H && this.get(nx, ny) === MATERIALS.EMPTY) {
                                            // Slide diagonally
                                            this.set(nx, ny, MATERIALS.SAND);
                                            this.set(x, y, MATERIALS.EMPTY);
                                            break; // Moved successfully, stop checking directions
                                        }
                                    }
                                }
                                break;

                            case MATERIALS.WATER:
                                // 1. Check straight down (like sand)
                                if (this.get(x, y + 1) === MATERIALS.EMPTY) {
                                    // Fall straight down
                                    this.set(x, y + 1, MATERIALS.WATER);
                                    this.set(x, y, MATERIALS.EMPTY);
                                } else {
                                    // 2. Spread horizontally (randomize direction)
                                    const directions = [
                                        { dx: -1 }, // Left
                                        { dx: 1 }   // Right
                                    ];
                                    directions.sort(() => Math.random() - 0.5);

                                    for (const dir of directions) {
                                        const nx = x + dir.dx;
                                        if (nx >= 0 && nx < GRID_W && this.get(nx, y) === MATERIALS.EMPTY) {
                                            // Spread horizontally
                                            this.set(nx, y, MATERIALS.WATER);
                                            this.set(x, y, MATERIALS.EMPTY);
                                            break; // Spread successfully, stop checking directions
                                        }
                                    }
                                }
                                break;

                            case MATERIALS.ACID:
                                // 1. Check straight down (like water)
                                if (this.get(x, y + 1) === MATERIALS.EMPTY) {
                                    // Fall straight down
                                    this.set(x, y + 1, MATERIALS.ACID);
                                    this.set(x, y, MATERIALS.EMPTY);
                                } else {
                                    // 2. Spread horizontally (like water)
                                    const directions = [
                                        { dx: -1 }, // Left
                                        { dx: 1 }   // Right
                                    ];
                                    directions.sort(() => Math.random() - 0.5);

                                    for (const dir of directions) {
                                        const nx = x + dir.dx;
                                        if (nx >= 0 && nx < GRID_W && this.get(nx, y) === MATERIALS.EMPTY) {
                                            // Spread horizontally
                                            this.set(nx, y, MATERIALS.ACID);
                                            this.set(x, y, MATERIALS.EMPTY);
                                            break; // Spread successfully, stop checking directions
                                        }
                                    }
                                }

                                // 3. Acid Dissolution Check (Check neighbors below and beside)
                                const checkNeighbors = [
                                    { nx: x - 1, ny: y + 1 }, // Left-Down
                                    { nx: x + 1, ny: y + 1 }, // Right-Down
                                    { nx: x, ny: y + 1 }      // Directly Down (already checked for movement)
                                ];

                                const checkSideNeighbors = [
                                    { nx: x - 1, ny: y }, // Left
                                    { nx: x + 1, ny: y }  // Right
                                ];

                                // Check below/beside targets for dissolution (only if they are not empty)
                                const dissolveTargets = [...checkNeighbors, ...checkSideNeighbors];

                                for (const target of dissolveTargets) {
                                    const tx = target.nx;
                                    const ty = target.ny;

                                    if (tx >= 0 && tx < GRID_W && ty >= 0 && ty < GRID_H) {
                                        const targetMaterial = this.get(tx, ty);

                                        // Acid dissolves sand or wall
                                        if ((targetMaterial === MATERIALS.SAND || targetMaterial === MATERIALS.WALL)) {
                                            // Dissolve: Remove the material and let it become empty
                                            this.set(tx, ty, MATERIALS.EMPTY);
                                        }
                                    }
                                }
                                break;

                            default:
                                // Walls or Empty - do nothing
                                break;
                        }
                    }
                }
            }
        };


        // --- RENDERING LOGIC ---

        /**
         * Draws the entire grid state onto the canvas.
         */
        sim.draw = function() {
            ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    const material = grid[y][x];
                    ctx.fillStyle = MATERIAL_COLORS[material] || '#000';
                    ctx.fillRect(x * CELL_PIXEL_SIZE, y * CELL_PIXEL_SIZE, CELL_PIXEL_SIZE, CELL_PIXEL_SIZE);

                    // Optional: Draw grid lines for better visibility (comment out if performance is critical)
                    ctx.strokeStyle = '#1a1a2e'; 
                    ctx.strokeRect(x * CELL_PIXEL_SIZE, y * CELL_PIXEL_SIZE, CELL_PIXEL_SIZE, CELL_PIXEL_SIZE);
                }
            }
        };

        // --- INPUT HANDLING (Painting) ---

        let isDrawing = false;

        /**
         * Converts mouse coordinates to grid cell indices.
         */
        function getGridCoords(event) {
            const rect = canvas.getBoundingClientRect();
            const scaleX = CANVAS_SIZE / rect.width;
            const scaleY = CANVAS_SIZE / rect.height;

            const clientX = event.clientX - rect.left;
            const clientY = event.clientY - rect.top;

            // Calculate coordinates relative to the canvas size (0 to 600)
            const xPixel = clientX * scaleX;
            const yPixel = clientY * scaleY;

            const x = Math.floor(xPixel / CELL_PIXEL_SIZE);
            const y = Math.floor(yPixel / CELL_PIXEL_SIZE);

            return { x: Math.min(Math.max(0, x), GRID_W - 1), y: Math.min(Math.max(0, y), GRID_H - 1) };
        }


        function handlePaintStart(event) {
            isDrawing = true;
            const coords = getGridCoords(event);
            sim.set(coords.x, coords.y, currentMaterial);
        }

        function handlePaintMove(event) {
            if (!isDrawing) return;
            const coords = getGridCoords(event);
            sim.set(coords.x, coords.y, currentMaterial);
        }

        function handlePaintEnd() {
            isDrawing = false;
        }


        // --- EVENT LISTENERS AND INITIAL SETUP ---

        document.addEventListener('DOMContentLoaded', () => {
            // 1. Initialize the simulation state
            sim.init();

            // 2. Setup Material Selectors
            const materialButtonsMap = document.getElementById('controls').querySelectorAll('button');
            materialButtonsMap.forEach(button => {
                button.addEventListener('click', () => {
                    currentMaterial = button.id.replace('mat-', '').toUpperCase();
                    // Ensure the internal constant name is used for consistency
                    if (currentMaterial === 'EMPTY') currentMaterial = MATERIALS.EMPTY;
                });
            });

            // 3. Setup Clear Button
            document.getElementById('clear').addEventListener('click', () => {
                if(confirm("Are you sure you want to clear the entire grid?")) {
                    sim.clear();
                }
            });

            // 4. Canvas Painting Listeners
            canvas.addEventListener('mousedown', handlePaintStart);
            canvas.addEventListener('mousemove', handlePaintMove);
            window.addEventListener('mouseup', handlePaintEnd); // Use window to catch mouseup outside canvas

            // Optional: Auto-run simulation loop (for visual satisfaction)
            setInterval(() => {
                sim._step();
            }, 100); // Run a step every 100ms
        });

    </script>
</body>
</html>
